import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    best_node = None
    max_priority = -float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        distance_to_customer = np.linalg.norm(customer_pos - cur_truck_pos)
        time_to_customer = distance_to_customer / truck_speed
        wait_time = max(0, time_windows[i][0] - current_time)

        visited_count = 0
        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, depot_pos):
                continue
            if np.linalg.norm(truck_pos - customer_pos) < distance_to_customer:
                visited_count += 1

        mid_time_window = (time_windows[i][0] + time_windows[i][1]) / 2
        time_difference = abs(current_time - mid_time_window)

        priority = -0.4 * distance_to_customer - 0.3 * visited_count - 0.3 * time_difference

        if current_time + time_to_customer + wait_time < time_windows[i][1]:
            if priority > max_priority:
                best_node = i
                max_priority = priority
        else:
            penalty = 10 * (time_windows[i][1] - current_time)
            if priority - penalty > max_priority:
                best_node = i
                max_priority = priority - penalty

    return best_node
